public class ShopManager : MonoBehaviour
{
    [SerializeField] private PlayerStats _playerStats;

    // Authoritative item catalog — prices defined here, not from client
    private static readonly ShopItemDefinition[] _itemCatalog = new ShopItemDefinition[]
    {
        new ShopItemDefinition
        {
            ItemId = "health_potion_small",
            DisplayName = "Small Health Potion",
            BasePrice = 50,
            MaxPurchaseCount = 99,
            Category = ShopItemDefinition.ItemCategory.HealthPotion
        },
        new ShopItemDefinition
        {
            ItemId = "health_potion_large",
            DisplayName = "Large Health Potion",
            BasePrice = 150,
            MaxPurchaseCount = 50,
            Category = ShopItemDefinition.ItemCategory.HealthPotion
        },
        new ShopItemDefinition
        {
            ItemId = "armor_upgrade_basic",
            DisplayName = "Basic Armor Upgrade",
            BasePrice = 300,
            MaxPurchaseCount = 10,
            Category = ShopItemDefinition.ItemCategory.Armor
        },
        new ShopItemDefinition
        {
            ItemId = "health_upgrade",
            DisplayName = "Max Health Upgrade",
            BasePrice = 500,
            MaxPurchaseCount = 20,
            Category = ShopItemDefinition.ItemCategory.Consumable
        }
    };

    // Track purchase counts to enforce limits
    private readonly System.Collections.Generic.Dictionary<string, int> _purchaseCounts =
        new System.Collections.Generic.Dictionary<string, int>();

    /// <summary>
    /// Attempt to purchase an item. All validation is authoritative.
    /// </summary>
    public PurchaseResult TryPurchase(string itemId)
    {
        if (string.IsNullOrEmpty(itemId))
        {
            return new PurchaseResult { Success = false, Reason = "Invalid item ID" };
        }

        // Look up item from authoritative catalog — never trust client-provided prices
        ShopItemDefinition item = GetItemFromCatalog(itemId);
        if (item == null)
        {
            Debug.LogWarning($"[SHOP] Unknown item ID rejected: {itemId}");
            return new PurchaseResult { Success = false, Reason = "Item not found" };
        }

        // Check purchase limits
        int currentPurchaseCount = 0;
        _purchaseCounts.TryGetValue(itemId, out currentPurchaseCount);

        if (currentPurchaseCount >= item.MaxPurchaseCount)
        {
            return new PurchaseResult { Success = false, Reason = "Purchase limit reached" };
        }

        // Use authoritative price — never accept price from client
        int authoritativePrice = GetAuthoritativePrice(item);

        // Check currency
        int playerCurrency = _playerStats.Currency;
        if (playerCurrency < authoritativePrice)
        {
            return new PurchaseResult
            {
                Success = false,
                Reason = "Insufficient currency",
                RequiredCurrency = authoritativePrice,
                CurrentCurrency = playerCurrency
            };
        }

        // Deduct currency through validated method
        if (!DeductCurrency(authoritativePrice))
        {
            return new PurchaseResult { Success = false, Reason = "Currency deduction failed" };
        }

        // Apply item effects authoritatively
        bool effectApplied = ApplyItemEffect(item);
        if (!effectApplied)
        {
            // Refund on failure — this should not normally happen
            _playerStats.AddCurrency(authoritativePrice, CurrencySource.GameplayReward, $"refund_{Guid.NewGuid()}");
            return new PurchaseResult { Success = false, Reason = "Failed to apply item effect" };
        }

        // Track purchase
        _purchaseCounts[itemId] = currentPurchaseCount + 1;

        return new PurchaseResult
        {
            Success = true,
            ItemId = itemId,
            PricePaid = authoritativePrice,
            RemainingCurrency = _playerStats.Currency
        };
    }

    private ShopItemDefinition GetItemFromCatalog(string itemId)
    {
        // Allowlist lookup — only items in the catalog can be purchased
        foreach (var item in _itemCatalog)
        {
            if (item.ItemId == itemId)
                return item;
        }
        return null;
    }

    /// <summary>
    /// Get the authoritative price for an item. This is the single source of truth for pricing.
    /// </summary>
    private int GetAuthoritativePrice(ShopItemDefinition item)
    {
        // Price is defined in the catalog, not derived from any client input
        return item.BasePrice;
    }

    private bool DeductCurrency(int amount)
    {
        if (amount <= 0) return false;

        int current = _playerStats.Currency;
        if (current < amount) return false;

        // Use negative addition through the validated AddCurrency path
        // We need a dedicated deduction method on PlayerStats
        return _playerStats.AddCurrency(-amount, CurrencySource.GameplayReward, $"purchase_{Guid.NewGuid()}");
    }

    private bool ApplyItemEffect(ShopItemDefinition item)
    {
        switch (item.Category)
        {
            case ShopItemDefinition.ItemCategory.HealthPotion:
                int healAmount = item.ItemId == "health_potion_small" ? 30 : 75;
                return _playerStats.Heal(healAmount, $"shop_{item.ItemId}");

            case ShopItemDefinition.ItemCategory.Armor:
                return _playerStats.UpgradeArmor(10, $"shop_{item.ItemId}");

            case ShopItemDefinition.ItemCategory.Consumable:
                if (item.ItemId == "health_upgrade")
                    return _playerStats.UpgradeMaxHealth(25, $"shop_{item.ItemId}");
                return false;

            default:
                return false;
        }
    }

    /// <summary>
    /// Get item info for UI display. Returns a copy, not a reference to the authoritative data.
    /// </summary>
    public ShopItemInfo GetItemInfo(string itemId)
    {
        var item = GetItemFromCatalog(itemId);
        if (item == null) return null;

        int purchaseCount = 0;
        _purchaseCounts.TryGetValue(itemId, out purchaseCount);

        return new ShopItemInfo
        {
            ItemId = item.ItemId,
            DisplayName = item.DisplayName,
            Price = GetAuthoritativePrice(item),
            RemainingPurchases = item.MaxPurchaseCount - purchaseCount,
            CanAfford = _playerStats.Currency >= GetAuthoritativePrice(item)
        };
    }

    /// <summary>
    /// Get all available items for UI display.
    /// </summary>
    public ShopItemInfo[] GetAllItems()
    {
        var items = new ShopItemInfo[_itemCatalog.Length];
        for (int i = 0; i < _itemCatalog.Length; i++)
        {
            items[i] = GetItemInfo(_itemCatalog[i].ItemId);
        }
        return items;
    }
}

