    {
        if (string.IsNullOrEmpty(receipt) || string.IsNullOrEmpty(transactionId))
        {
            Debug.LogWarning("[IAP] Empty receipt or transaction ID");
            return false;
        }

        // Prevent replay attacks — each transaction ID can only be used once
        if (_verifiedTransactions.Contains(transactionId))
        {
            Debug.LogWarning($"[IAP] Duplicate transaction ID rejected: {transactionId}");
            return false;
        }

        // TODO: In production, send receipt to YOUR backend server for validation
        // Your server should validate with Apple App Store / Google Play
        // Never validate receipts solely on the client
        //
        // Example flow:
        // 1. Client sends receipt to your server
        // 2. Your server validates with Apple/Google
        // 3. Your server returns success/failure
        // 4. Client marks transaction as verified only on server confirmation

        // Placeholder — replace with actual server validation
        bool serverValidated = ValidateWithServer(receipt, transactionId);

        if (serverValidated)
        {
            _verifiedTransactions.Add(transactionId);
        }

        return serverValidated;
    }

    public static bool IsTransactionVerified(string transactionId)
    {
