/// <summary>
/// Handles encrypted save/load operations.
/// In production, use platform-specific secure storage (Keychain on iOS, Keystore on Android).
/// </summary>
public static class SecureSaveManager
{
    // In production, derive this from platform keystore, not hardcoded
    private static byte[] _encryptionKey;
    private static byte[] _hmacKey;
    private static bool _initialized = false;

    private static void EnsureInitialized()
    {
        if (_initialized) return;

        // Generate or retrieve keys from secure platform storage
        // On iOS: use Keychain
        // On Android: use Android Keystore
        // This is a simplified version — in production use platform APIs

        string storedKeyB64 = PlayerPrefs.GetString("_ek", "");
        string storedHmacB64 = PlayerPrefs.GetString("_hk", "");

        if (string.IsNullOrEmpty(storedKeyB64) || string.IsNullOrEmpty(storedHmacB64))
        {
            _encryptionKey = new byte[32];
            _hmacKey = new byte[32];
            using (var rng = new RNGCryptoServiceProvider())
            {
                rng.GetBytes(_encryptionKey);
                rng.GetBytes(_hmacKey);
            }
            // NOTE: In production, store these in platform secure storage, NOT PlayerPrefs
            PlayerPrefs.SetString("_ek", Convert.ToBase64String(_encryptionKey));
            PlayerPrefs.SetString("_hk", Convert.ToBase64String(_hmacKey));
            PlayerPrefs.Save();
        }
        else
        {
            _encryptionKey = Convert.FromBase64String(storedKeyB64);
            _hmacKey = Convert.FromBase64String(storedHmacB64);
        }

        _initialized = true;
    }

    public static string Encrypt(string plaintext)
    {
        EnsureInitialized();

        try
        {
            using (var aes = Aes.Create())
            {
                aes.Key = _encryptionKey;
                aes.GenerateIV();
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;

                using (var encryptor = aes.CreateEncryptor())
                {
                    byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
                    byte[] ciphertext = encryptor.TransformFinalBlock(plaintextBytes, 0, plaintextBytes.Length);

                    // Prepend IV to ciphertext
                    byte[] result = new byte[aes.IV.Length + ciphertext.Length];
                    Buffer.BlockCopy(aes.IV, 0, result, 0, aes.IV.Length);
                    Buffer.BlockCopy(ciphertext, 0, result, aes.IV.Length, ciphertext.Length);

                    return Convert.ToBase64String(result);
                }
            }
        }
        catch (Exception ex)
        {
            Debug.LogError($"[SECURITY] Encryption failed: {ex.GetType().Name}");
            return null;
        }
    }

    public static string Decrypt(string encryptedBase64)
    {
        EnsureInitialized();

        try
        {
            byte[] encryptedBytes = Convert.FromBase64String(encryptedBase64);

            using (var aes = Aes.Create())
            {
                aes.Key = _encryptionKey;
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;

                // Extract IV from beginning
                byte[] iv = new byte[16];
                Buffer.BlockCopy(encryptedBytes, 0, iv, 0, 16);
                aes.IV = iv;

                byte[] ciphertext = new byte[encryptedBytes.Length - 16];
                Buffer.BlockCopy(encryptedBytes, 16, ciphertext, 0, ciphertext.Length);

                using (var decryptor = aes.CreateDecryptor())
                {
                    byte[] plaintext = decryptor.TransformFinalBlock(ciphertext, 0, ciphertext.Length);
                    return Encoding.UTF8.GetString(plaintext);
                }
            }
        }
        catch (Exception ex)
        {
            Debug.LogError($"[SECURITY] Decryption failed: {ex.GetType().Name}");
            return null;
        }
    }

    public static string ComputeSaveHash(string data)
    {
        EnsureInitialized();

        using (var hmac = new HMACSHA256(_hmacKey))
        {
            byte[] hash = hmac.ComputeHash(Encoding.UTF8.GetBytes(data));
            return Convert.ToBase64String(hash);
        }
    }
}

/// <summary>
/// Combat manager that uses authoritative damage calculations.
/// </summary>
public class CombatManager : MonoBehaviour
{
    [SerializeField] private PlayerStats _playerStats;

    /// <summary>
    /// Process an enemy attack against the player.
    /// Enemy stats are looked up authoritatively, not passed from client.
    /// </summary>
    public DamageResult ProcessEnemyAttack(string enemyId, string attackId)
    {
        if (string.IsNullOrEmpty(enemyId) || string.IsNullOrEmpty(attackId))
        {
            return new DamageResult { Success = false, Reason = "Invalid enemy or attack ID" };
        }

        // Look up enemy attack data from authoritative source
        EnemyAttackData attackData = GetAuthoritativeAttackData(enemyId, attackId);
        if (attackData == null)
        {
            Debug.LogWarning($"[COMBAT] Unknown enemy/attack combination: {enemyId}/{attackId}");
            return new DamageResult { Success = false, Reason = "Unknown attack" };
        }

        // Damage calculation uses authoritative data only
        return _playerStats.ApplyDamage(attackData.BaseDamage, attackData.Type, $"{enemyId}_{attackId}");
    }

    private EnemyAttackData GetAuthoritativeAttackData(string enemyId, string attackId)
    {
        // In production, this would be loaded from encrypted/signed game data files
        // This is a simplified authoritative lookup
        string key = $"{enemyId}_{attackId}";

        // Allowlisted enemy attacks
        switch (key)
        {
            case "goblin_slash": return new EnemyAttackData { BaseDamage = 10, Type = DamageType.Physical };
            case "goblin_throw": return new EnemyAttackData { BaseDamage = 8, Type = DamageType.Physical };
            case "mage_fireball": return new EnemyAttackData { BaseDamage = 25, Type = DamageType.Magical };
            case "mage_frostbolt": return new EnemyAttackData { BaseDamage = 20, Type = DamageType.Magical };
            case "dragon_breath": return new EnemyAttackData { BaseDamage = 50, Type = DamageType.Magical };
            case "dragon_claw": return new EnemyAttackData { BaseDamage = 40, Type = DamageType.Physical };
            case "trap_spike": return new EnemyAttackData { BaseDamage = 15, Type = DamageType.Environmental };
            default: return null;
        }
    }

    private class EnemyAttackData
    {
        public int BaseDamage;
        public DamageType Type;
    }
}